        return 0 <= x < w and 0 <= y < h and (x, y) not in obstacles

    def md(x1, y1, x2, y2):
        return abs(x1 - x2) + abs(y1 - y2)

    def best_move_for_target(tx, ty):
        best = None
        bestd = 10**9
        for dx, dy in deltas:
